        'sys_id' => HUIFU_SYS_ID,
        'huifu_id' => HUIFU_HUIFU_ID,
        'product_id' => HUIFU_PRODUCT_ID,
        'notify_url' => HUIFU_NOTIFY_URL,
        'sign_type' => HUIFU_SIGN_TYPE,
        'test_mode' => HUIFU_TEST_MODE,
